if doc.unit_serial_number:
    unit = frappe.get_doc("Rental Item Unit", doc.unit_serial_number)

    new_condition = unit.unit_condition

    if doc.workflow_state == "Attention Required" and doc.unit_condition:
        new_condition = doc.unit_condition
    elif doc.workflow_state == "Complete" and doc.final_condition:
        new_condition = doc.final_condition

    if new_condition != unit.unit_condition:
        unit.db_set(
            "unit_condition",
            new_condition,
            update_modified=True,
            notify=False  # suppress the message
        )

# Server-side sync and calculation
if doc.unit_type == "Box":
    # 1. Sync Child Table conditions from the linked Serial Numbers
    if doc.item_unit_list:
        for item in doc.item_unit_list:
            if item.unit_serial_number:
                # Fetch current condition of the specific unit from DB
                latest_cond = frappe.db.get_value("Rental Item Unit", 
                    {"unit_serial_number": item.unit_serial_number}, "unit_condition")
                
                if latest_cond:
                    item.unit_condition = latest_cond

        # 2. Calculate the Cumulative Condition for the Box
        conditions = [d.unit_condition for d in doc.item_unit_list if d.unit_condition]
        
        if conditions:
            unique_conditions = list(set(conditions))
            
            # If all are same (e.g. all OK), use that. If mixed, use 'Partially Ok'
            new_cond = unique_conditions[0] if len(unique_conditions) == 1 else "Partially Ok"
            
            if doc.unit_condition != new_cond:
                doc.unit_condition = new_cond

# DocType: Rental Movement | Event: After Save
tx = doc.transaction_type

for row in doc.get("rental_item_unit_child_table"):
    if not row.unit_doc_id:
        continue

    # Get live state
    master = frappe.get_doc("Rental Item Unit", row.unit_doc_id)
    
    # Server-side Safety Check
    if tx == 'CHECK_OUT' and (master.movement_status != 'Warehouse' or master.unit_condition != 'OK'):
        frappe.throw(f"Validation Error for {master.unit_serial_number}: Item must be in Warehouse and OK.")

    # Calculate Values
    new_status = master.movement_status
    new_location = master.unit_location

    if tx == 'CHECK_OUT':
        new_status = 'At Event'
        new_location = doc.to_location
    elif tx in ['CHECK_IN', 'MAINTENANCE_IN']:
        new_status = 'Warehouse'
        new_location = 'Main Warehouse'
    elif tx == 'MAINTENANCE_OUT':
        new_status = 'In Maintenance'
        new_location = 'Repair Shop'
    elif tx == 'LOST':
        new_status = 'Missing'
        new_location = 'Unknown'

    # Update Master
    frappe.db.set_value("Rental Item Unit", master.name, {
        "unit_location": new_location,
        "movement_status": new_status,
        "unit_condition": row.unit_condition
    })

    # Sync Row
    frappe.db.set_value("Rental Item Unit Child Table", row.name, {
        "unit_location": new_location,
        "movement_status": new_status
    })

def before_validate(self):
    if self.rental_item_type_box == "Bulk":
        # Provide default placeholder for all dependent fields
        if not self.suffix:
            self.suffix = "NONE"

        if not self.sku_naming_series:
            self.sku_naming_series = "NONE"

        if not self.sku_character_count:
            self.sku_character_count = 0  # numeric default; or "NONE" if field allows text

        # Ignore mandatory checks just in case
        self.flags.ignore_mandatory = True

units = doc.get("rental_item_unit_child_table") or []

for row in units:
    unit_name = row.get("unit_doc_id")
    if unit_name:
        unit = frappe.get_doc("Rental Item Unit", unit_name)
        template_name = unit.item_template

        if template_name:
            # Count all units for the template
            total_units = frappe.db.count("Rental Item Unit", {"item_template": template_name})

            # Get current template values as integers
            template_doc = frappe.get_doc("Rental Item Template", template_name)
            available_units = int(template_doc.available_quantity or total_units)
            total_quantity = int(template_doc.total_quantity or total_units)

            # Adjust based on transaction type
            if doc.transaction_type == "CHECK_OUT":
                available_units -= 1

            elif doc.transaction_type == "CHECK_IN":
                available_units += 1

            elif doc.transaction_type == "MAINTENANCE_OUT":
                available_units -= 1

            elif doc.transaction_type == "MAINTENANCE_IN":
                available_units += 1

            elif doc.transaction_type == "LOST":
                total_quantity -= 1
                available_units -= 1

            elif doc.transaction_type == "PURCHASE":
                total_quantity += 1
                available_units += 1

            elif doc.transaction_type == "DISPOSE":
                total_quantity -= 1
                available_units -= 1

            # Clamp values safely
            available_units = max(0, min(available_units, total_quantity))
            total_quantity = max(0, total_quantity)

            # Update the template
            frappe.db.set_value("Rental Item Template", template_name, {
                "total_quantity": total_quantity,
                "available_quantity": available_units
            })

rows = doc.get("table_udfz") or []

for row in rows:
    template_name = row.item_template
    if not template_name:
        continue

    move_qty = int(row.amount or 0)
    if move_qty <= 0:
        continue

    template_doc = frappe.get_doc("Rental Item Template", template_name)

    # Initialize if empty
    if not template_doc.total_quantity:
        template_doc.total_quantity = int(row.data_dgaq or 0)
    if not template_doc.available_quantity:
        template_doc.available_quantity = int(row.data_dgaq or 0)

    total_qty = int(template_doc.total_quantity)
    available_qty = int(template_doc.available_quantity)

    # Apply movement
    if doc.transaction_type == "CHECK_OUT":
        available_qty -= move_qty
    elif doc.transaction_type == "CHECK_IN":
        available_qty += move_qty
    elif doc.transaction_type == "MAINTENANCE_OUT":
        available_qty -= move_qty
    elif doc.transaction_type == "MAINTENANCE_IN":
        available_qty += move_qty
    elif doc.transaction_type == "LOST":
        total_qty -= move_qty
        available_qty -= move_qty
    elif doc.transaction_type == "PURCHASE":
        total_qty += move_qty
        available_qty += move_qty
    elif doc.transaction_type == "DISPOSE":
        total_qty -= move_qty
        available_qty -= move_qty

    # Clamp
    available_qty = max(0, min(available_qty, total_qty))
    total_qty = max(0, total_qty)

    # Update DB
    frappe.db.set_value("Rental Item Template", template_name, {
        "total_quantity": total_qty,
        "available_quantity": available_qty
    })

    # Update doc in memory so it shows on form
    template_doc.total_quantity = total_qty
    template_doc.available_quantity = available_qty
